from agent import *from models.products import *debug = Truedef process_revlist(data: Response, context: dict[str, str], session: Session):    revs = data.xpath("//*[@class='ipsSpacer_both' or @class='ipsType_break']//a")    for rev in revs:        title = rev.xpath(".//text()").string()        url = rev.xpath("@href").string()        if '/reviews/' in url:            session.queue(Request(url, use='curl'), process_review, dict(context, title=title, url=url))        nexturl = data.xpath("//li[@class='ipsPagination_next']/a/@href").string()    if nexturl:        session.queue(Request(nexturl, use='curl'), process_revlist, dict(context))def process_review(data: Response, context: dict[str, str], session: Session):    product = Product()    product.name = context['title'].split(' Review')[0]    product.ssid = context['url'].split('/')[-2].replace('.html', '')    product.category = data.xpath("((//nav/following-sibling::ul)[last()]/li)[last()-1]//text()").string(multiple=True)    product.url = context['url']        review = Review()    review.title = context['title']    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']    review.date = data.xpath("//div[@class='metaFont metaDate']/abbr[@class='published']//text()").string().split('T')[0]        authors = data.xpath("//div[@class='postMeta--author-author metaFont']/a")    for author in authors:        author_name = author.xpath(".//text()").string()        author_url = author.xpath("@href").string()        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_name))        excerpt = data.xpath("//div[@class='ipsClearfix']//p//text()").string(multiple=True)    if excerpt:        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))        pros = data.xpath("//div[@class='ipsClearfix']//p/span[contains(.,'+')]/..//text()")    for pro in pros:        pro = pro.string().replace('+', '').strip()        if pro:            review.add_property(type='pros', value=pro)        cons = data.xpath("//div[@class='ipsClearfix']//p/span[contains(.,'-')]/..//text()")    for con in cons:        con = con.string().replace('-', '').strip()        if con:            review.add_property(type='cons', value=con)                product.reviews.append(review)    session.emit(product)def run(context: dict[str, str], session: Session):    session.queue(Request('https://www.thelab.gr/reviews/', use='curl'), process_revlist, {})